use std::{
    collections::HashMap,
    sync::{
        Arc,
        atomic::{AtomicU64, Ordering},
    },
    time::{SystemTime, UNIX_EPOCH},
};

use axum::{
    Json, Router,
    extract::State,
    http::{HeaderMap, StatusCode},
    response::{IntoResponse, Response},
    routing::{get, post},
};
use serde::Serialize;
use tokio::sync::RwLock;

use crate::entities::{
    AssignTaskRequest, CreateTaskRequest, EmailLog, LoginRequest, Role, Task, User,
    VerifyTwoFactorRequest,
};

type ApiResult<T> = Result<(StatusCode, Json<T>), ApiError>;

#[derive(Clone)]
struct AppState {
    store: Arc<RwLock<Store>>,
    sequence: Arc<AtomicU64>,
}

#[derive(Default)]
struct Store {
    users: HashMap<u64, User>,
    pending_codes: HashMap<String, String>,
    sessions: HashMap<String, u64>,
    email_logs: Vec<EmailLog>,
    tasks: HashMap<u64, Task>,
}

#[derive(Serialize)]
struct LoginResponse {
    message: &'static str,
    requires_2fa: bool,
}

#[derive(Serialize)]
struct VerifyTwoFactorResponse {
    token: String,
    token_type: &'static str,
}

#[derive(Serialize)]
struct SeedUsersResponse {
    message: &'static str,
    users: Vec<User>,
    development_password: &'static str,
}

#[derive(Debug)]
struct ApiError {
    status: StatusCode,
    message: String,
}

impl ApiError {
    fn new(status: StatusCode, message: impl Into<String>) -> Self {
        Self {
            status,
            message: message.into(),
        }
    }
}

impl IntoResponse for ApiError {
    fn into_response(self) -> Response {
        (
            self.status,
            Json(serde_json::json!({ "error": self.message })),
        )
            .into_response()
    }
}

pub fn app() -> Router {
    let state = AppState {
        store: Arc::new(RwLock::new(Store::default())),
        sequence: Arc::new(AtomicU64::new(1)),
    };

    Router::new()
        .route("/seed/users", post(seed_users))
        .route("/auth/login", post(login))
        .route("/dev/email-logs/latest", get(latest_email_log))
        .route("/auth/verify-2fa", post(verify_two_factor))
        .route("/tasks", post(create_task))
        .route("/tasks/assign", post(assign_task))
        .route("/tasks/view-my-tasks", get(view_my_tasks))
        .with_state(state)
}

async fn seed_users(State(state): State<AppState>) -> ApiResult<SeedUsersResponse> {
    let mut store = state.store.write().await;
    if !store.users.is_empty() {
        return Err(ApiError::new(
            StatusCode::CONFLICT,
            "users have already been seeded",
        ));
    }

    let users = vec![
        User {
            id: 1,
            name: "Admin User".into(),
            email: "admin@example.com".into(),
            role: Role::Admin,
            password: "password123".into(),
        },
        User {
            id: 2,
            name: "Task User".into(),
            email: "user@example.com".into(),
            role: Role::User,
            password: "password123".into(),
        },
    ];

    for user in &users {
        store.users.insert(user.id, user.clone());
    }

    Ok((
        StatusCode::CREATED,
        Json(SeedUsersResponse {
            message: "users seeded",
            users,
            development_password: "password123",
        }),
    ))
}

async fn login(
    State(state): State<AppState>,
    Json(payload): Json<LoginRequest>,
) -> ApiResult<LoginResponse> {
    let email = payload.email.trim().to_ascii_lowercase();
    let mut store = state.store.write().await;
    let valid_credentials = store
        .users
        .values()
        .any(|user| user.email == email && user.password == payload.password);

    if !valid_credentials {
        return Err(ApiError::new(
            StatusCode::UNAUTHORIZED,
            "invalid email or password",
        ));
    }

    let code = format!(
        "{:06}",
        state.sequence.fetch_add(1, Ordering::Relaxed) % 1_000_000
    );
    store.pending_codes.insert(email.clone(), code.clone());
    store.email_logs.push(EmailLog {
        to: email,
        subject: "Your two-factor authentication code".into(),
        body: format!("Your verification code is {code}"),
        code,
        created_at: unix_timestamp(),
    });

    Ok((
        StatusCode::OK,
        Json(LoginResponse {
            message: "verification code sent",
            requires_2fa: true,
        }),
    ))
}

async fn latest_email_log(State(state): State<AppState>) -> ApiResult<EmailLog> {
    let store = state.store.read().await;
    let log = store.email_logs.last().cloned().ok_or_else(|| {
        ApiError::new(StatusCode::NOT_FOUND, "no development email logs found")
    })?;

    Ok((StatusCode::OK, Json(log)))
}

async fn verify_two_factor(
    State(state): State<AppState>,
    Json(payload): Json<VerifyTwoFactorRequest>,
) -> ApiResult<VerifyTwoFactorResponse> {
    let email = payload.email.trim().to_ascii_lowercase();
    let mut store = state.store.write().await;
    let expected_code = store.pending_codes.get(&email).ok_or_else(|| {
        ApiError::new(StatusCode::UNAUTHORIZED, "no verification is pending")
    })?;

    if expected_code != payload.code.trim() {
        return Err(ApiError::new(
            StatusCode::UNAUTHORIZED,
            "invalid verification code",
        ));
    }

    let user_id = store
        .users
        .values()
        .find(|user| user.email == email)
        .map(|user| user.id)
        .ok_or_else(|| ApiError::new(StatusCode::UNAUTHORIZED, "user no longer exists"))?;
    let token = format!(
        "session-{}-{}",
        user_id,
        state.sequence.fetch_add(1, Ordering::Relaxed)
    );

    store.pending_codes.remove(&email);
    store.sessions.insert(token.clone(), user_id);

    Ok((
        StatusCode::OK,
        Json(VerifyTwoFactorResponse {
            token,
            token_type: "Bearer",
        }),
    ))
}

async fn create_task(
    State(state): State<AppState>,
    headers: HeaderMap,
    Json(payload): Json<CreateTaskRequest>,
) -> ApiResult<Task> {
    let user_id = authenticate(&state, &headers).await?;
    let title = payload.title.trim();
    if title.is_empty() {
        return Err(ApiError::new(StatusCode::BAD_REQUEST, "title is required"));
    }

    let id = state.sequence.fetch_add(1, Ordering::Relaxed);
    let task = Task {
        id,
        title: title.into(),
        description: payload
            .description
            .map(|value| value.trim().to_string())
            .filter(|value| !value.is_empty()),
        created_by: user_id,
        assigned_to: None,
        created_at: unix_timestamp(),
    };
    state.store.write().await.tasks.insert(id, task.clone());

    Ok((StatusCode::CREATED, Json(task)))
}

async fn assign_task(
    State(state): State<AppState>,
    headers: HeaderMap,
    Json(payload): Json<AssignTaskRequest>,
) -> ApiResult<Task> {
    let current_user_id = authenticate(&state, &headers).await?;
    let mut store = state.store.write().await;

    if !store.users.contains_key(&payload.user_id) {
        return Err(ApiError::new(StatusCode::NOT_FOUND, "assignee not found"));
    }

    let task = store
        .tasks
        .get_mut(&payload.task_id)
        .ok_or_else(|| ApiError::new(StatusCode::NOT_FOUND, "task not found"))?;
    if task.created_by != current_user_id {
        return Err(ApiError::new(
            StatusCode::FORBIDDEN,
            "only the task creator can assign this task",
        ));
    }

    task.assigned_to = Some(payload.user_id);
    Ok((StatusCode::OK, Json(task.clone())))
}

async fn view_my_tasks(
    State(state): State<AppState>,
    headers: HeaderMap,
) -> ApiResult<Vec<Task>> {
    let user_id = authenticate(&state, &headers).await?;
    let store = state.store.read().await;
    let mut tasks: Vec<_> = store
        .tasks
        .values()
        .filter(|task| task.assigned_to == Some(user_id))
        .cloned()
        .collect();
    tasks.sort_by_key(|task| task.id);

    Ok((StatusCode::OK, Json(tasks)))
}

async fn authenticate(state: &AppState, headers: &HeaderMap) -> Result<u64, ApiError> {
    let token = headers
        .get("authorization")
        .and_then(|value| value.to_str().ok())
        .and_then(|value| value.strip_prefix("Bearer "))
        .filter(|value| !value.is_empty())
        .ok_or_else(|| ApiError::new(StatusCode::UNAUTHORIZED, "bearer token is required"))?;

    state
        .store
        .read()
        .await
        .sessions
        .get(token)
        .copied()
        .ok_or_else(|| ApiError::new(StatusCode::UNAUTHORIZED, "invalid bearer token"))
}

fn unix_timestamp() -> u64 {
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap_or_default()
        .as_secs()
}

