use std::{
    collections::HashMap,
    sync::{
        Arc,
        atomic::{AtomicU64, Ordering},
    },
    time::{SystemTime, UNIX_EPOCH},
};

use axum::{
    Json, Router,
    extract::State,
    http::{HeaderMap, StatusCode},
    response::{IntoResponse, Response},
    routing::{get, post},
};
use serde::Serialize;
use tokio::sync::RwLock;

use crate::entities::{
    AssignTaskRequest, CreateTaskRequest, EmailLog, LoginRequest, Role, Task, User,
    VerifyTwoFactorRequest,
};

type ApiResult<T> = Result<(StatusCode, Json<T>), ApiError>;

// I do not understand this now;
