}

#[derive(Serialize)]
struct SeedUsersResponse {
    message: &'static str,
    users: Vec<User>,
    development_credentials: Vec<DevelopmentCredential>,
}

#[derive(Serialize)]
struct DevelopmentCredential {
    email: &'static str,
    password: &'static str,
